mapper.select:
select c.id, c.access_number, c.iccid, c.imsi, c.msisdn, c.imei, c.operator, c.card_status, c.total_data, c.data_used, c.data_remaining, c.activate_time, c.expire_time, c.down_time, c.device_id, c.card_platform_id, c.data_alert_threshold, c.notify_users, c.data_plan, c.tenant_id, c.tenant_name, c.create_by, c.create_time, c.update_by, c.update_time, cp.platform from iot_card c left join iot_card_platform cp on c.card_platform_id = cp.id
c.del_flag = 0 and cp.del_flag = 0
and c.card_status = #{cardVO.cardStatus}
